const errData = $input.first().json;
console.log(JSON.stringify({ timestamp: new Date().toISOString(), route: 'nf_service_labels', event: 'db_error', message: errData.message || 'Unknown DB error', level: 'error' }));
return { statusCode: 500, body: { ok: false, error: 'Database error', message: 'Could not update service labels' } };

const affectedRecords = $input.all().length;
console.log(JSON.stringify({ timestamp: new Date().toISOString(), route: 'nf_service_labels', event: 'service_labels_upserted', labels_updated: affectedRecords, level: 'info' }));
return { statusCode: 200, body: { message: 'Data extracted, cleaned, and converted to DataFrame successfully' } };

const ctx = $input.first().json;
const labels = Array.isArray(ctx.labels) ? ctx.labels : [];

function normalizeStatus(rawStatus) {
  const normalized = String(rawStatus || '').trim().toUpperCase();
  if (normalized === 'ATIVO' || normalized === 'INATIVO') return normalized;
  return 'ATIVO';
}

const transformed = labels.map((label, index) => {
  const codigo = String(label.codigo || label.Codigo || label.codigo_servico || label.contas || label.Contas || '').trim();
  if (!codigo) {
    console.log(JSON.stringify({ timestamp: new Date().toISOString(), route: 'nf_service_labels', event: 'label_skipped_no_codigo', label_index: index, level: 'warn' }));
    return null;
  }
  return {
    codigo_servico: codigo,
    contas: String(label.contas || label.Contas || '').trim(),
    boletos: String(label.boletos || label.Boletos || '').trim(),
    nota: String(label.nota || label.Nota || '').trim(),
    cliente: String(label.cliente || label.Cliente || '').trim(),
    status: normalizeStatus(label.status || label.Status),
    vendedor: String(label.vendedor || label.Vendedor || '').trim(),
    chave: String(label.chave || label.Chave || '').trim(),
    numeronfs: String(label.numeronfs || label.NumeroNfs || label.NumeroNFS || '').trim(),
    notarecibo: String(label.notarecibo || label.NotaRecibo || '').trim(),
    vinculooscomnfs: String(label.vinculooscomnfs || label.VinculoOsComNfs || '').trim(),
    runned: String(label.runned || label.Runned || '').trim()
  };
}).filter(Boolean);

console.log(JSON.stringify({ timestamp: new Date().toISOString(), route: 'nf_service_labels', event: 'labels_transformed', valid_labels: transformed.length, total_input: labels.length, level: 'info' }));

return transformed;

const rawInput = $input.first().json;
const body = rawInput.body || rawInput;

function parseHtmlTableFromCdata(rawText) {
  if (!rawText || typeof rawText !== 'string') return [];
  const cdataMatch = rawText.match(/<!\[CDATA\[([\s\S]*?)\]\]>/i);
  const html = cdataMatch ? cdataMatch[1] : rawText;
  const rowMatches = [...html.matchAll(/<tr[^>]*>([\s\S]*?)<\/tr>/gi)];
  if (!rowMatches.length) return [];

  const rows = rowMatches.map(r => r[1]);
  const dataRows = rows.slice(1);
  const parsed = [];

  for (const row of dataRows) {
    const cellMatches = [...row.matchAll(/<t[dh][^>]*>([\s\S]*?)<\/t[dh]>/gi)];
    const cells = cellMatches.map(c => String(c[1] || '').replace(/<[^>]*>/g, '').trim());
    if (!cells.length) continue;

    parsed.push({
      codigo: cells[0] || '',
      contas: cells[1] || '',
      boletos: cells[2] || '',
      nota: cells[3] || '',
      cliente: cells[4] || '',
      status: cells[5] || 'ATIVO',
      vendedor: cells[6] || '',
      chave: cells[7] || '',
      numeronfs: cells[8] || '',
      notarecibo: cells[9] || '',
      vinculooscomnfs: cells[10] || '',
      runned: cells[11] || ''
    });
  }

  return parsed;
}

let labels = [];
if (body && body.data && Array.isArray(body.data.labels)) labels = body.data.labels;
if (!labels.length) {
  const rawText = typeof body === 'string' ? body : (typeof rawInput === 'string' ? rawInput : '');
  labels = parseHtmlTableFromCdata(rawText);
}

if (!Array.isArray(labels) || labels.length === 0) {
  return { _valid: false, statusCode: 400, body: { ok: false, error: 'Missing or invalid labels payload (JSON or CDATA)' } };
}

console.log(JSON.stringify({ timestamp: new Date().toISOString(), route: 'nf_service_labels', event: 'input_validated', labels_count: labels.length, level: 'info' }));
return { _valid: true, labels: labels };
